package io.helidon.common.buffers;

import java.io.InputStream;
import java.io.OutputStream;
import java.nio.ByteBuffer;
import java.nio.charset.Charset;
import java.util.ArrayList;
import java.util.LinkedList;
import java.util.List;

class CompositeListBufferData extends ReadOnlyBufferData implements CompositeBufferData {
    private final List<BufferData> data;

    CompositeListBufferData() {
        this.data = new LinkedList<>();
    }

    CompositeListBufferData(BufferData initial) {
        this.data = new LinkedList<>();
        this.data.add(initial);
    }

    CompositeListBufferData(List<BufferData> data) {
        this.data = new ArrayList<>(data);
    }

    @Override
    public CompositeBufferData add(BufferData bufferData) {
        data.add(bufferData);
        return this;
    }

    @Override
    public BufferData rewind() {
        for (BufferData datum : data) {
            datum.rewind();
        }
        return this;
    }

    @Override
    public void writeTo(OutputStream out) {
        if (data.size() == 1) {
            BufferData datum = data.get(0);
            if (!(datum instanceof CompositeBufferData)) {
                datum.writeTo(out);
                return;
            }
        }
        copy().writeTo(out);
    }

    @Override
    public int readFrom(InputStream in) {
        for (BufferData datum : data) {
            if (datum.capacity() > 0) {
                return datum.readFrom(in);
            }
        }
        throw new IllegalStateException("The composite buffer is fully written, cannot write additional bytes");
    }

    @Override
    public int readFrom(ByteBuffer buf) {
        for (BufferData datum : data) {
            if (datum.capacity() > 0) {
                return datum.readFrom(buf);
            }
        }
        throw new IllegalStateException("The composite buffer is fully written, cannot write additional bytes");
    }

    @Override
    public int read() {
        for (BufferData datum : data) {
            if (!datum.consumed()) {
                return datum.read();
            }
        }

        throw new ArrayIndexOutOfBoundsException("This buffer has no more bytes");
    }

    @Override
    public int read(byte[] buffer, int position, int length) {
        int myPosition = position;
        int remaining = length;

        for (BufferData datum : data) {
            if (datum.available() > 0) {
                int read = datum.read(buffer, myPosition, remaining);
                myPosition += read;
                remaining -= read;
                if (remaining == 0) {
                    break;
                }
            }
        }

        return myPosition - position;
    }

    @Override
    public String readString(int length, Charset charset) {
        byte[] buffer = new byte[length];

        int read = read(buffer, 0, length);
        if (read != length) {
            throw new ArrayIndexOutOfBoundsException("Requested " + length + "bytes, but only " + read + " were available");
        }
        return new String(buffer, charset);
    }

    @Override
    public boolean consumed() {
        boolean consumed = true;

        for (BufferData datum : data) {
            if (!datum.consumed()) {
                consumed = false;
            }
        }

        return consumed;
    }

    @Override
    public int writeTo(ByteBuffer writeBuffer, int limit) {
        int written = 0;

        for (BufferData datum : data) {
            if (datum.consumed()) {
                continue;
            }
            int datumWrote = datum.writeTo(writeBuffer, limit - written);
            if (datumWrote == 0) {
                // not consumed and wrote 0 -> full
                break;
            }
            written += datumWrote;
        }

        return written;
    }

    @Override
