    }

    @Override
    public void close() {
        try {
            // if close() is called without shutdownOutput(), the remote sometimes does not receive last bytes sent
            delegate.shutdownOutput();
            delegate.shutdownInput();
            delegate.close();
        } catch (IOException e) {
            throw new UncheckedIOException(e);
        }
    }

    @Override
    public void idle() {
    }

