package io.helidon.common.socket;

import java.io.ByteArrayOutputStream;
import java.io.IOException;
import java.nio.ByteBuffer;
import java.nio.channels.SocketChannel;

import io.helidon.common.buffers.BufferData;

import org.junit.jupiter.api.Test;

import static org.hamcrest.MatcherAssert.assertThat;
import static org.hamcrest.Matchers.is;
import static org.mockito.ArgumentMatchers.any;
import static org.mockito.Mockito.mock;
import static org.mockito.Mockito.when;

class NioSocketTest {

    @Test
    void writeRetriesPartialChannelWrites() throws IOException {
        byte[] data = "0123456789abcdef".getBytes();
        ByteArrayOutputStream written = new ByteArrayOutputStream();
        SocketChannel channel = mock(SocketChannel.class);

        when(channel.write(any(ByteBuffer.class))).thenAnswer(invocation -> {
            ByteBuffer buffer = invocation.getArgument(0);
            int toWrite = Math.min(3, buffer.remaining());
            byte[] bytes = new byte[toWrite];
            buffer.get(bytes);
            written.write(bytes);
            return toWrite;
        });

        NioSocket.server(channel, "child", "server").write(BufferData.create(data));

        assertThat(written.toByteArray(), is(data));
    }
}

